class JSONFormatter(logging.Formatter):
    """JSON log formatter for structured logging."""

    def format(self, record):
        log_entry = {
            'timestamp': datetime.now(timezone.utc).isoformat(),
            'level': record.levelname,
            'logger': record.name,
            'message': record.getMessage(),
            'module': record.module,
            'function': record.funcName,
            'line': record.lineno,
        }

        # Add extra fields if present
        for attr in ['request_id', 'method', 'path', 'status_code',
                     'duration_ms', 'remote_addr', 'user_id', 'user_email',
                     'request_headers', 'request_body', 'response_summary',
                     'error_type', 'error_traceback', 'content_length']:
            if hasattr(record, attr):
                log_entry[attr] = getattr(record, attr)

        if record.exc_info and record.exc_info[0] is not None:
            log_entry['exception'] = self.formatException(record.exc_info)

        return json.dumps(log_entry, default=str)


class ReadableFormatter(logging.Formatter):
    """Human-readable formatter for console output."""

    COLORS = {
        'DEBUG': '\033[36m',     # Cyan
        'INFO': '\033[32m',      # Green
        'WARNING': '\033[33m',   # Yellow
        'ERROR': '\033[31m',     # Red
        'CRITICAL': '\033[35m',  # Magenta
    }
    RESET = '\033[0m'

    def format(self, record):
        color = self.COLORS.get(record.levelname, self.RESET)
        timestamp = datetime.now(timezone.utc).strftime('%Y-%m-%d %H:%M:%S.%f')[:-3]

        request_id = getattr(record, 'request_id', '-')
        base = f'{timestamp} {color}{record.levelname:8s}{self.RESET} [{request_id[:8]}] {record.getMessage()}'

        extras = []
        if hasattr(record, 'method') and hasattr(record, 'path'):
            extras.append(f"  → {record.method} {record.path}")
        if hasattr(record, 'status_code'):
            extras.append(f"  → Status: {record.status_code}")
        if hasattr(record, 'duration_ms'):
            extras.append(f"  → Duration: {record.duration_ms:.2f}ms")
        if hasattr(record, 'remote_addr'):
            extras.append(f"  → Client: {record.remote_addr}")
        if hasattr(record, 'user_email'):
            extras.append(f"  → User: {record.user_email}")
        if hasattr(record, 'error_type'):
            extras.append(f"  → Error: {record.error_type}")

        if extras:
            base += '\n' + '\n'.join(extras)

        if record.exc_info and record.exc_info[0] is not None:
            base += '\n' + self.formatException(record.exc_info)

        return base


